/**
 * Get bundled TLE data for a constellation ID
 * Maps sat-globe constellation IDs to TLE group keys
 */
const CONS_TO_GROUP = {
  "gps-ops": "gps-ops",
  "glo-ops": "glo-ops",
  "galileo": "galileo",
  "beidou": "beidou",
  "iridium-next": "iridium-next",
  "globalstar": "globalstar",
  "orbcomm": "orbcomm",
  "goes": "weather",
  "noaa-polar": "weather",
  "stations": "stations",
  "starlink": "starlink",
  "oneweb": "oneweb",
  "geo-intelsat": "intelsat",
  "geo-ses": "ses",
  "geo-eutelsat": "ses",
  "o3b": "ses",
};

export function getBundledTLE(constellationId) {
  const groupId = CONS_TO_GROUP[constellationId] || constellationId;
  const raw = BUNDLED_TLE[groupId] || [];
  return raw.map(([name, tle1, tle2]) => ({ name, tle1, tle2 }));
}